import{_ as r,C as n,o as t,c as s,a2 as a,b as d,w as i,a as l,E as c,a3 as h}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"en/technical/security.md","filePath":"en/technical/security.md"}'),u={name:"en/technical/security.md"};function p(m,e,b,g,y,f){const o=n("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>Overview of the security measures implemented in Nid.</p><hr><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><h3 id="httponly-jwt" tabindex="-1">httpOnly JWT <a class="header-anchor" href="#httponly-jwt" aria-label="Permalink to &quot;httpOnly JWT&quot;">​</a></h3><p>JWT tokens are stored in <strong>httpOnly cookies</strong>, inaccessible to client-side JavaScript. This protects against XSS attacks that would attempt to steal tokens.</p><ul><li><strong>Access token</strong>: short duration (15 min by default), used for every API request</li><li><strong>Refresh token</strong>: long duration (30 days by default), used only to renew the access token</li></ul><h3 id="redis-jwt-blacklist" tabindex="-1">Redis JWT Blacklist <a class="header-anchor" href="#redis-jwt-blacklist" aria-label="Permalink to &quot;Redis JWT Blacklist&quot;">​</a></h3><p>On logout, the token is added to a Redis blacklist. The <code>authenticate</code> middleware checks this blacklist on every request, enabling <strong>immediate invalidation</strong> of a compromised token.</p><h3 id="password-hashing" tabindex="-1">Password Hashing <a class="header-anchor" href="#password-hashing" aria-label="Permalink to &quot;Password Hashing&quot;">​</a></h3><p>Passwords are hashed with <strong>bcrypt</strong> (12 rounds). A dummy hash is computed even when the user doesn&#39;t exist, which prevents account enumeration through timing attacks.</p><h3 id="rate-limiting" tabindex="-1">Rate Limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate Limiting&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Route</th><th>Limit</th></tr></thead><tbody><tr><td><code>POST /api/auth/register</code></td><td>3 requests / minute</td></tr><tr><td><code>POST /api/auth/login</code></td><td>5 requests / minute</td></tr><tr><td>General routes</td><td>100 requests / minute / IP</td></tr></tbody></table><h3 id="_2fa-totp" tabindex="-1">2FA TOTP <a class="header-anchor" href="#_2fa-totp" aria-label="Permalink to &quot;2FA TOTP&quot;">​</a></h3><p>Two-factor authentication is optional for local accounts. It uses <strong>TOTP</strong> (RFC 6238) via <code>otplib</code>, with QR code generation for setup.</p><h3 id="multi-provider-sso" tabindex="-1">Multi-Provider SSO <a class="header-anchor" href="#multi-provider-sso" aria-label="Permalink to &quot;Multi-Provider SSO&quot;">​</a></h3><p>Social Login uses the <strong>Arctic</strong> library with server-side OAuth2 code exchange. Social tokens never transit through the frontend.</p><p>Supported providers: Google, Microsoft, Discord, Facebook, LinkedIn, Keycloak.</p><hr><h2 id="authorization" tabindex="-1">Authorization <a class="header-anchor" href="#authorization" aria-label="Permalink to &quot;Authorization&quot;">​</a></h2><h3 id="multi-user-isolation" tabindex="-1">Multi-User Isolation <a class="header-anchor" href="#multi-user-isolation" aria-label="Permalink to &quot;Multi-User Isolation&quot;">​</a></h3><p>Two Fastify decorators ensure data isolation:</p><ul><li><strong><code>requireAccountOwnership</code></strong> — Verifies that the <code>:accountId</code> parameter belongs to the authenticated user. Applied on all Gmail, archive, dashboard, and rules routes.</li><li><strong><code>requireAdmin</code></strong> — Verifies that <code>role === &#39;admin&#39;</code> in the JWT. Applied on admin and integrity routes.</li></ul>',23)),(t(),d(h,null,{default:i(()=>[c(o,{id:"mermaid-118",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20REQ%5BRequ%C3%AAte%20HTTP%5D%20--%3E%20AUTH%5Bauthenticate%5D%0A%20%20%20%20AUTH%20--%3E%20OWN%7BrequireAccountOwnership%7D%0A%20%20%20%20OWN%20--%3E%7COK%7C%20HANDLER%5BHandler%20route%5D%0A%20%20%20%20OWN%20--%3E%7C403%7C%20REJECT%5BAcc%C3%A8s%20refus%C3%A9%5D%0A%20%20%20%20%0A%20%20%20%20AUTH%20--%3E%20ADM%7BrequireAdmin%7D%0A%20%20%20%20ADM%20--%3E%7COK%7C%20ADMIN_HANDLER%5BHandler%20admin%5D%0A%20%20%20%20ADM%20--%3E%7C403%7C%20REJECT%0A"})]),fallback:i(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h3 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Role</th><th>Access</th></tr></thead><tbody><tr><td><code>user</code></td><td>Own data (emails, archives, rules, jobs, notifications)</td></tr><tr><td><code>admin</code></td><td>Same + administration page (users, global jobs, quotas, integrity)</td></tr></tbody></table><hr><h2 id="input-validation" tabindex="-1">Input Validation <a class="header-anchor" href="#input-validation" aria-label="Permalink to &quot;Input Validation&quot;">​</a></h2><p>All user inputs are validated with <strong>Zod</strong>:</p><ul><li>Strict schemas on request bodies, query params, and URL parameters</li><li>TypeScript types inferred from Zod schemas</li><li>Automatic rejection of unknown fields</li></ul><p>Full-text search uses <code>plainto_tsquery</code> (not <code>to_tsquery</code>), which neutralizes query operators and protects against PostgreSQL operator injection.</p><hr><h2 id="archive-encryption" tabindex="-1">Archive Encryption <a class="header-anchor" href="#archive-encryption" aria-label="Permalink to &quot;Archive Encryption&quot;">​</a></h2><p>EML archives can be encrypted at rest on the NAS:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Value</th></tr></thead><tbody><tr><td>Algorithm</td><td>AES-256-GCM (confidentiality + integrity)</td></tr><tr><td>Key derivation</td><td>PBKDF2 (SHA-512, 100,000 iterations)</td></tr><tr><td>Salt</td><td>32 random bytes per file</td></tr><tr><td>IV</td><td>12 random bytes per file</td></tr><tr><td>Passphrase storage</td><td>Scrypt hash in database — never the passphrase itself</td></tr></tbody></table><h3 id="binary-format" tabindex="-1">Binary Format <a class="header-anchor" href="#binary-format" aria-label="Permalink to &quot;Binary Format&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GMENC01 (7 B) | SALT (32 B) | IV (12 B) | AUTH_TAG (16 B) | CIPHERTEXT</span></span></code></pre></div><ul><li>Magic bytes <code>GMENC01</code> for encrypted file detection</li><li>On-the-fly decryption without temporary files</li><li>Idempotency: already encrypted files are skipped</li></ul><hr><h2 id="network-security" tabindex="-1">Network Security <a class="header-anchor" href="#network-security" aria-label="Permalink to &quot;Network Security&quot;">​</a></h2><h3 id="production" tabindex="-1">Production <a class="header-anchor" href="#production" aria-label="Permalink to &quot;Production&quot;">​</a></h3><ul><li>PostgreSQL and Redis are <strong>not exposed</strong> on the host</li><li>Only port 3000 (Nginx) is accessible</li><li>CORS configured for <code>FRONTEND_URL</code> only</li></ul><h3 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h3><p>Webhooks of type <code>generic</code> include an <code>X-Webhook-Signature</code> header containing an HMAC-SHA256 of the payload, allowing the recipient to verify the request&#39;s authenticity.</p><hr><h2 id="file-security" tabindex="-1">File Security <a class="header-anchor" href="#file-security" aria-label="Permalink to &quot;File Security&quot;">​</a></h2><ul><li>Filenames in <code>Content-Disposition</code> headers are sanitized</li><li>File paths are validated to prevent directory traversal</li><li>EML files are identified by UUID, not by user-provided paths</li></ul><hr><h2 id="audit" tabindex="-1">Audit <a class="header-anchor" href="#audit" aria-label="Permalink to &quot;Audit&quot;">​</a></h2><p>All sensitive actions are tracked in the audit log:</p><table tabindex="0"><thead><tr><th>Category</th><th>Tracked Actions</th></tr></thead><tbody><tr><td>Authentication</td><td>Login, logout, registration, failed login</td></tr><tr><td>Gmail accounts</td><td>Account connection, disconnection</td></tr><tr><td>Rules</td><td>Creation, modification, deletion, execution</td></tr><tr><td>Bulk operations</td><td>Deletion, archiving, label modification</td></tr><tr><td>Configuration</td><td>Export, import</td></tr><tr><td>Administration</td><td>User modification, role change</td></tr></tbody></table><p>Each entry includes the request&#39;s IP address for traceability.</p><hr><h2 id="docker-container-security" tabindex="-1">Docker Container Security <a class="header-anchor" href="#docker-container-security" aria-label="Permalink to &quot;Docker Container Security&quot;">​</a></h2><h3 id="base-images" tabindex="-1">Base Images <a class="header-anchor" href="#base-images" aria-label="Permalink to &quot;Base Images&quot;">​</a></h3><ul><li><strong>Alpine images</strong> — Systematic use of Alpine variants to reduce the attack surface (fewer binaries, fewer potential CVEs)</li><li><strong>Updates</strong> — <code>apk upgrade --no-cache</code> in production to apply security patches</li></ul><h3 id="multi-stage-build" tabindex="-1">Multi-Stage Build <a class="header-anchor" href="#multi-stage-build" aria-label="Permalink to &quot;Multi-Stage Build&quot;">​</a></h3><p>Dockerfiles use a <strong>multi-stage build</strong> (builder → deps → runner) so the final image contains:</p><ul><li>No source code</li><li>No devDependencies</li><li>No build tools (npm, corepack, yarn)</li></ul><h3 id="non-root-user" tabindex="-1">Non-Root User <a class="header-anchor" href="#non-root-user" aria-label="Permalink to &quot;Non-Root User&quot;">​</a></h3><p>All production images run with a <strong>non-root user</strong> (<code>appuser:appgroup</code>, UID/GID 1001). This limits the impact of a potential compromise of the Node.js process.</p><h3 id="dockerignore" tabindex="-1"><code>.dockerignore</code> <a class="header-anchor" href="#dockerignore" aria-label="Permalink to &quot;`.dockerignore`&quot;">​</a></h3><p><code>.dockerignore</code> files prevent copying sensitive files into the build context:</p><ul><li><code>.env</code>, <code>.env.*</code>, <code>*.pem</code>, <code>*.key</code> — Environment variables and secrets</li><li><code>.git</code> — Git history</li><li><code>node_modules</code>, <code>coverage</code>, <code>dist</code> — Build artifacts</li><li><code>volumes/</code> — User data</li></ul><h3 id="internal-network" tabindex="-1">Internal Network <a class="header-anchor" href="#internal-network" aria-label="Permalink to &quot;Internal Network&quot;">​</a></h3><p>In production, PostgreSQL and Redis are <strong>not exposed</strong> on the host — they communicate only through the Docker internal network. Only port 3000 (Nginx) is accessible.</p><h3 id="ignore-scripts" tabindex="-1"><code>--ignore-scripts</code> <a class="header-anchor" href="#ignore-scripts" aria-label="Permalink to &quot;`--ignore-scripts`&quot;">​</a></h3><p>Production <code>npm ci</code> commands use <code>--ignore-scripts</code> to prevent execution of potentially malicious <code>postinstall</code> scripts in dependencies.</p>',44))])}const A=r(u,[["render",p]]);export{q as __pageData,A as default};
